var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"룰렛 테이블에 여자애 둘이서 코인을 다 쓸어담고 있대!","JPN":"ルーレットテーブルで女の子二人がコインを全部取ってるんだって！","ENG":"Did you hear? Two girls are racking up coins at the roulette table!","TWN":"聽說有二個小女生橫掃俄羅斯輪盤欸！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"듣자 하니 룰렛 확률을 계산한다던데? 지금까지 백전백승이라나 봐!","JPN":"なんでもルーレットの確率を計算してるらしいよ？　今まで百戦百勝だそうだ！","ENG":"I heard they're calculating roulette probabilities. They've won every game so far!","TWN":"她們好像會計算骰子的機率，目前為止似乎是百戰百勝欸！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"말도 안 돼! 슈퍼 AI가 아니고서야 그런 게 가능할 리 없잖아?","JPN":"まさか！　スーパーAIでもなけりゃそんなの不可能だろ？","ENG":"No way! Not even a super AI can do that, right?!","TWN":"誇張！根本是AI吧？否則怎麼可能？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"시그마, 이런 게임은 처음이라고 하지 않았어?","JPN":"シグマ、こういうゲームは初めてって言ってなかった？","ENG":"Sigma, didn't you say that was the first time you ever played these kinds of games?","TWN":"西格瑪，你不是說你是第一次玩輪盤嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"엣헴.","JPN":"えっへん。","ENG":"Ahem!","TWN":"嘿嘿。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"진짜 대단했어. 가면 찾는 것도 깜빡 잊을 만큼…….","JPN":"本当にすごかったよ。仮面を探すのもうっかり忘れるほどに……","ENG":"That was amazing. Enough so that I completely forgot about looking for my mask...","TWN":"真是精彩，精彩到我都忘記要找面具這回事……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"아차……! 깜빡하면 안 되는데!","JPN":"しまった……！　うっかりしちゃダメなのに！","ENG":"Oh no...! I have to look for it!","TWN":"哎呀……！忘記可不行！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"애초에 이런 방식의 게임에서 확실한 수를 계산한다는 게 말이 안 되지. 일반적이라면.","JPN":"だいたい、こういった方式のゲームで確実な数を計算するってことはあり得ない。一般的には。","ENG":"Normally, calculating the probabilities of these types of games is impossible.","TWN":"基本上這種遊戲本來就無法計算正確的數字。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"시그마, 네 연산 능력은 대체 얼마나 좋은 거야?","JPN":"シグマの演算能力の高さっていったいどのくらいなの？","ENG":"Sigma, how good are your calculating abilities anyway?","TWN":"西格瑪，你的運算能力到底有多強？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"하늘만큼 땅만큼 아빠 사랑만큼!","JPN":"天くらい、地くらい、パパの愛くらい！","ENG":"As good as heaven and earth, and Daddy's love!","TWN":"像天、像地、像爸爸的愛那樣強！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……하나도 못 알아듣겠어.","JPN":"……さっぱりわからないよ。","ENG":"...I don't understand any of your words.","TWN":"……聽不懂你在說什麼。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"자, 자! 얘들아! 조금만 더 분발하자!","JPN":"さあさあ！　みんな！　もうちょっと頑張ろう！","ENG":"All right, you guys! Just a little bit more!","TWN":"來吧來吧！大家再加點油！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이대로 가면 내 집 장만이 아니라 빌딩도 세우겠어!","JPN":"この調子で行けば家だけじゃなくてビルも建てられるよ！","ENG":"At this rate, forget about buying a house! I'll be able to get an entire building!","TWN":"再贏下去，不只是房子的頭期款，整棟我都可以直接付現金買下來咧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"우리가 지금 돈 벌러 왔냐? 아까 위저드 애들 운운한 거 벌써 잊었어?","JPN":"お金儲けに来たわけじゃないだろ？　さっきのウィザードの子ども云々の話をもう忘れたの？","ENG":"Hey, we're not here to make money, you know. Or did you already forget about our objective to help the Wizard kids here?","TWN":"我們是來贏錢的嗎？剛剛是誰說巫師的孩子們怎麼辦的？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"벌 수 있을 때 벌어 둬야지. 내가 아니면 너희 오늘 헛물 켜고 돌아갔어.","JPN":"稼げるときに稼いでおかないと。私がいなかったら、アンタたちは今日何もできずに帰ってたはずだよ。","ENG":"Gotta make bank while you can, am I right? If it weren't for me, this whole operation would've already failed.","TWN":"當然要趁能賺的時候趕快先賺起來嘛，要不是我你們今天早就空手而歸咧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"틀렸어, 도로시. 쟤 눈이 동전 모양이야.","JPN":"諦めよう、ドロシーちゃん。あの人目がコインの形になってる。","ENG":"Give up, Dorothy. Her eyes are even turning into Haven Coins.","TWN":"糟糕，桃樂絲，她現在眼裡只看得到錢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"한창 즐기고 있는데 미안하군.","JPN":"楽しんでいる途中、すまない。","ENG":"I'm sorry to interrupt you while you're having such a good time.","TWN":"不好意思，你們玩得正開心，打擾你們。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"흐억……!","JPN":"ふあっ……！","ENG":"Oh no...!","TWN":"唔……！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"루트, 왜 숨어? 숨바꼭질이 더 하고 싶어?","JPN":"ルート、なんで隠れるの？　かくれんぼ、もっとしたい？","ENG":"Root? Why are you hiding? Do you want to play more hide-and-seek?","TWN":"路特，你躲起來幹嘛？你還想玩躲貓貓喔？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"아, 아니. 그냥 반사적으로…….","JPN":"あ、いや。つい……","ENG":"N-no... I-it's just a reflex...","TWN":"不…不是，就下意識……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"엄청난 신예들이 나타났다고 하더군. 벌써 10만 코인 넘게 벌었다지?","JPN":"とんでもない新鋭が現われたと聞いてな。もう10万コイン以上稼いだそうじゃないか。","ENG":"You girls seem to be the talk of today. You've already earned more than 100k coins, am I right?","TWN":"我聽說出現一群厲害的新手，已經贏超過10萬？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응! 아저씨도 우리랑 게임할래?","JPN":"うん！　おじさんも私たちとゲームする？","ENG":"Uh-huh! Do you want to play with us too?","TWN":"嗯！叔叔也要和我們一起玩嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"얼마든지 덤벼. 혼쭐을 내 줄 테니까.","JPN":"いつでもかかってこい。ぎゃふんと言わせてやる。","ENG":"Bring it on. I'll rip you a new one.","TWN":"儘管來吧，讓你知道我們的厲害。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"하하. 미안하지만 나는 판에 끼지 않아. 형님과 약속했거든.","JPN":"はは。悪いが俺はゲームには参加しないんだ。兄貴と約束したんでね。","ENG":"Ha ha. Sorry, but I don't play myself. It's a promise I made to Mr. Haven.","TWN":"哈哈，不好意思，我不會上賭桌，這是我和大哥的約定。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"잠시 나와 얘기 좀 나눌 수 있겠나?","JPN":"俺と少し話さないか？","ENG":"Can I have a word with you in private?","TWN":"方便和我聊幾句嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"대체 뭐예요, 아저씨? 우리가 사기라도 쳤을까 봐요?","JPN":"いったい何ですか、おじさん？　イカサマしたって思ってるんですか？","ENG":"Who the heck are you, mister? Are you accusing us of cheating?","TWN":"大叔，你到底想幹嘛？是怕我們耍詐嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"우리 쪽 딜러들도 실력 있는 사람과 사기꾼은 구분할 줄 알아.","JPN":"我々のディーラーも実力のある人間と詐欺師の区別はつく。","ENG":"Our dealers are able to discern cheaters from skilled players.","TWN":"我們的莊家還分得出誰是有實力的賭客，誰是老千的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"그저 궁금했을 뿐이지. 어디에 쓰려고 코인을 그렇게 쓸어 담는 건지 말이야.","JPN":"ただ気になっていただけだよ。どこに使うためにそんなにコインを稼いでるのかがね。","ENG":"I'm just curious about what you're going to do with all those coins.","TWN":"我只是有點好奇，你們賺這麼多錢是要做什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그거야 당연히 빌딩……","JPN":"それはもちろんビルを……","ENG":"Because we're gonna buy a buil–","TWN":"當然是要買房……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"도전장을 사려고.","JPN":"挑戦状を買うためだよ。","ENG":"Challenge whoever's in charge here.","TWN":"買挑戰券！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L44_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……이 아니라, 맞아. 도전장을 구입하려고.","JPN":"……じゃなくて、そう。挑戦状を購入しようと思って。","ENG":"…Right. We're going to buy a ticket for the challenge.","TWN":"……對啦，買挑戰券。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"뭐? 도전장?","JPN":"何？　挑戦状？","ENG":"Huh? Challenge?","TWN":"什麼？挑戰券？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"하하! 그렇군! 나도 참, 이거야 원!","JPN":"はは！　そうか！　これは、やれやれ！","ENG":"Ha ha! I see! Now it all makes sense!","TWN":"哈哈！原來是這樣！就這點小事！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"이봐, 딜러!","JPN":"おい、ディーラー！","ENG":"Hey, dealer!","TWN":"喂，莊家！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DEALER_NPC_HAVEN_NULL","text":{"KOREA":"예, 허드슨 님. 부르셨습니까.","JPN":"はい、ハドソン様。お呼びですか？","ENG":"Yes, Mr. Hudson. You called?","TWN":"是，哈德森先生，請問有什麼吩咐？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEALER_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L1_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"이 친구들이 도전장을 사고 싶다는군. 당장 준비해 줘.","JPN":"この子たちが挑戦状を買いたいんだと。すぐに準備してくれ。","ENG":"These kids want to pay for the challenge. Get everything ready right away.","TWN":"他們說想要買挑戰券，你馬上去準備一下。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEALER_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"허드슨? 설마 허드슨 님?!","JPN":"ハドソン？　まさかハドソン様！？","ENG":"Hudson? You mean, THE Hudson?!","TWN":"哈德森？是那個哈德森？！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐야, 아는 사람이었어?","JPN":"何、知ってる人？","ENG":"Huh? You know this person?","TWN":"怎樣？你認識喔？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"당연하지! 그 살벌하다는 로터스를 휘젓고 다니다가 헤이븐 형님 밑에 들어온 분이라고!","JPN":"当たり前でしょ！　ヘイブン兄貴の部下で、以前はあの恐ろしいロータスでも有名だったっていう方なんだよ！","ENG":"Of course! He's the gangster who ruled the ruthless city, Lotus, before coming to work for Mr. Haven!","TWN":"當然認識！他在治安敗壞的洛德斯可是橫著走的，後來才到天堂大哥底下做事！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이렇게 만나 뵙다니 영광입니다!","JPN":"お会いできて光栄です！","ENG":"It's an honor to meet you, sir!","TWN":"沒想到會在這裡遇到你，真是榮幸。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"나야말로 영광이지. 이거 살다 보니 조카뻘인 애한테 칭찬도 다 듣는군.","JPN":"俺こそ光栄だ。甥にあたる歳の子どもに褒められるなんてこともあるんだな。","ENG":"The honor's all mine. After all these years, who know I'd get compliments from a young girl like you?","TWN":"我才榮幸，活到這把歲數，還能聽到年輕人對我的讚美。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DEALER_NPC_HAVEN_NULL","text":{"KOREA":"10만 헤이븐 코인 수령했습니다. 여기, 도전장을 받으시죠.","JPN":"10万ヘイブンコイン、ちょうどいただきました。挑戦状をどうぞ。","ENG":"I have confirmed receiving 100k Haven Coins. Here is your challenge ticket.","TWN":"收您10萬天堂幣，這是挑戰券。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEALER_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"좋아. 아저씨, 여기 담당자는 어디 있어?","JPN":"よし。おじさん、ここの担当者はどこにいるかわかる？","ENG":"All right! Hey mister, who's in charge here anyway?","TWN":"好，大叔，這裡的負責人是誰？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"나다. 오랜만에 도전을 받으니 설레는군.","JPN":"俺だ。久々の挑戦でワクワクするな。","ENG":"I am. I'm excited to get challenged in such a long time.","TWN":"就是我，好久沒收到挑戰，有點緊張呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앗! 아저씨였어?","JPN":"あっ！　おじさんだったの？","ENG":"Oh! You're?","TWN":"喔！就是叔叔喔？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"좋아! 이번엔 어떤 게임이야? 뭐든 다 이겨 줄게!","JPN":"よーし！　今度はどんなゲーム？　どんなのでも勝ってみせるよ！","ENG":"Okay! What game are we playing this time? I'll win 'em all!","TWN":"好欸！那這次要玩什麼？不管什麼遊戲我都會贏的！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"하하, 자신감이 굉장한데.","JPN":"はは、大した自信だな。","ENG":"Haha! I admire your confidence.","TWN":"哈哈，自信心爆棚喔！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"하지만 그렇게 호락호락하진 않을 거다. 여태까지 했던 게임과는 조금 다를 테니까.","JPN":"だが、そんなに簡単ではないぞ。今までのゲームとは少し違うはずだからな。","ENG":"But it's not gonna be easy. Because this game is going to be different from the other games you've played.","TWN":"不過我也不是好欺負的，這和你們目前玩過的遊戲不太一樣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"으응? 다르다니?","JPN":"うーん？　違うって？","ENG":"Hmm? Different?","TWN":"嗯？怎樣不一樣？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"건강한 몸에 건강한 정신이 깃드는 법. 우리 헤이븐 형님께서 내게 해 주신 말씀이지.","JPN":"健康な身体には健康な精神が宿るもの。ヘイブン兄貴が俺にくれた言葉だ。","ENG":"A healthy mind has a healthy body. That's what Mr. Haven taught me.","TWN":"有強健的體魄才有健康的心靈，這是我們天堂大哥說的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"도박에 빠져서 시들어가던 내가 이렇게 살아 있는 것도, 다 형님 덕분이야.","JPN":"ギャンブルにはまって死にかけていた俺がこうやって生きているのも、兄貴のおかげなんだ。","ENG":"He's the only reason why I'm not wasting my life away in some gambling ring.","TWN":"原本身陷賭博無法自拔的我，現在能站在這裡，也都是托大哥的福。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저기 봐! 벽이 열렸어!","JPN":"あっち見て！　壁が開いたよ！","ENG":"Hey look! The wall just opened up!","TWN":"你們看！牆打開咧！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오오! 비밀기지 같아! 멋지다!","JPN":"おお！　秘密基地みたい！　カッコいい！","ENG":"Ooh! It's like a secret base! So cool!","TWN":"哇喔！好像秘密基地喔！超酷！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"허드슨…….","JPN":"ハドソン……","ENG":"Hudson...","TWN":"哈德森……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 형님께서 내게 이걸 해 보라고 제안하신 이후, 나는 제 2의 인생을 찾게 되었다.","JPN":"ヘイブン兄貴にこれをやってみろと言われて以来、俺は第二の人生を見つけたんだ。","ENG":"After Mr. Haven suggested I try \\"this\\", I was reborn.","TWN":"天堂大哥建議我嘗試這個後，我便找到人生的第二春。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"그건 바로……","JPN":"それは……","ENG":"And \\"this\\" is...","TWN":"而那就是……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"조심해. 검색해 보니까 용병 시절에는 맨손으로 침식체 목을 꺾었다는 무용담도 있어.","JPN":"気をつけて。検索してみたら、傭兵をやっていた頃は素手で侵食体の首を折ったという武勇伝もある。","ENG":"Careful. There are stories of him snapping the neck of a C.O. with nothing but his bare hands in his mercenary days.","TWN":"小心，根據我搜尋的結果，有傳聞說他在傭兵時期，曾經徒手扭斷侵蝕體的脖子。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어차피 허풍이겠지. 어디 덤벼 보라고 해.","JPN":"どうせデマだろ。どっからでもかかってこい。","ENG":"Those stories are always fluffed up. Let's see what he's got.","TWN":"應該只是江湖傳言吧，出手吧！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"스포츠 댄스!","JPN":"スポーツダンス！","ENG":"Dancesport!","TWN":"國標舞！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L40_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……어?","JPN":"……あ？","ENG":"...Huh?","TWN":"……咦？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……댄스?","JPN":"……ダンス？","ENG":"…Dancing?","TWN":"……跳舞？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"와라, 도전자들! 무대 위에서 나와 춤 실력을 겨루는 거다!","JPN":"来い、挑戦者ども！　ステージの上で、俺と一緒にダンスの実力を競うのだ！","ENG":"Bring it on, challengers! Come up on stage and let's see who's got the better moves!","TWN":"來吧，挑戰者！在舞台上和我一較高下吧！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아니, 잠깐! 잠깐!! 허드슨 님은 베테랑 용병 출신이잖아요!","JPN":"いや、ちょっと！　待って！！　ハドソン様はベテラン傭兵出身じゃないですか！","ENG":"W-wait! Hold on a sec! Aren't you an ex-mercenary veteran, Mr. Hudson?!","TWN":"欸，等等等等！哈德森先生之前不是很老練的傭兵嗎！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이럴 때는 살벌한 분위기에 어울리게 권총으로 하는 룰렛이죠!","JPN":"こういう時には、血なまぐさい雰囲気に合わせて拳銃でやるルーレットでしょ！","ENG":"Shouldn't you be, like, challenging us to a game of Russian Roulette or something?","TWN":"在這種殺戮的氣氛之下，應該來個輪盤槍吧？"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"그건 사람이 다치잖아. 헤이븐 랜드는 다 함께 걱정 없이 즐기기 위한 곳이다.","JPN":"それでは怪我人が出るだろう。ヘイブンランドはみんなで一緒に心置きなく楽しむための場所なんだ。","ENG":"But then someone would get hurt. Havenland is where anyone can enjoy themselves without a worry in the world.","TWN":"那會受傷吧？天堂樂園是大家可以無憂無慮玩樂的地方。"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어…….","JPN":"え……","ENG":"Uh...","TWN":"喔……"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어쩌지. 내가 상상하던 헤이븐이랑 전혀 달라.","JPN":"どうしよう。私が想像してたヘイブンと全然違う。","ENG":"What do we do? This is way different from what I had in mind.","TWN":"怎麼辦？和我想像中的天堂完全不一樣。"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"나한테 말하지 마. 헷갈리는 건 마찬가지니까.","JPN":"私に言わないでよ。こっちも混乱してるんだから。","ENG":"What are you asking me for? I'm just as confused as you are.","TWN":"別問我，我跟你一樣混亂。"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"건강한 몸! 건강한 정신!","JPN":"健康な身体！　健康な精神！","ENG":"Healthy body! Healthy mind!","TWN":"強健的體魄！健康的心靈！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L4_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"춤은 우리의 감수성을 키워 주면서 운동도 할 수 있는 일석이조의 완벽한 활동이지!","JPN":"ダンスは感性を育ててくれると同時に運動もできてしまう、まさに一石二鳥の完璧な活動なんだ！","ENG":"With dancing you can get exercise while also getting in touch with your emotions, killing two birds with one stone!","TWN":"跳舞不只可以修身養性，同時還可以運動，根本是一石二鳥的完美行為！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"정신없이 몸을 움직이면 돈 몇 푼에 매달리던 자기 모습을 또렷하게 자각할 수 있거든.","JPN":"無我夢中で身体を動かしていると、小銭何個にすがりついていた己の姿をはっきりと自覚できるんだ。","ENG":"You will realize how much of a fuss you've made for a penny once you start moving to the rhythm.","TWN":"盡情地擺動身體後，就可以看清自己執著於那一點錢的樣貌。"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"도박판을 전전할 뿐인…… 들개 같았던 시절의 나처럼 말이야.","JPN":"賭場を転々とするだけの……野良犬みたいだった頃の俺と同じようにな。","ENG":"Just like... how I used to crawl from one gambling table to the next.","TWN":"就像那時候的我一樣，是個流連於賭桌的……賭鬼。"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 형님 말씀대로, 게임은 어디까지나 즐기기 위한 것.","JPN":"ヘイブン兄貴の言葉どおり、ゲームはどこまでも楽しむためのもの。","ENG":"Mr. Haven is right! Games are meant to be joyous!","TWN":"天堂大哥說過，遊戲的目的是要人能夠盡情享樂，"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"몸과 마음을 춤으로 다스리면 지나치게 몰입할 걱정도 없지!","JPN":"身体と心をダンスで鍛えれば、やりすぎる心配もない！","ENG":"But if you control your mind and body through dance, there is no worrying about getting too immersed!","TWN":"但只要透過跳舞來控制身體和心靈，就不怕過度投入！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"저…… 혹시 그 말, 적당히 지어냈을 거라는 생각은 안 들어요?","JPN":"あの……その言葉、適当に作ったかもしれないとは思わないんですか？","ENG":"Uh... Have you ever thought that your boss might've made that up on the spot?","TWN":"那個……你不覺得那句話是隨口說說的嗎？"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"그 말은 우리 형님이 아무 생각 없이 사는 분이라는 건가?","JPN":"それはつまり、兄貴がなんの考えもなしに生きている方だと言いたいのか？","ENG":"Are you saying that Mr. Haven is some foolish man?","TWN":"你的意思是我們大哥是說話不經大腦的人嗎？"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"히익……! 아뇨! 그런 뜻이 아니라요!","JPN":"ひいっ……！　いいえ！　そうじゃなくて！","ENG":"Eeeek! N-no! I didn't mean it like that!","TWN":"唔……！不是！我沒這個意思！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"……흠.","JPN":"……ふむ。","ENG":"Hmm...","TWN":"……哼。"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"형님 패션만 잘 따라했지, 마음가짐은 그렇지 못하군. 분발하는 게 좋을 거야.","JPN":"兄貴のファッションだけはうまく真似ているが、心構えまだまだだな。もっと頑張った方がいいぞ。","ENG":"Though you've mastered his style and looks, you haven't mastered his mindset. I suggest you do better.","TWN":"只學到皮毛沒學到精髓，勸你再多用點心吧！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"아, 그…… 네. 충고 감사합니다.","JPN":"あ、その……はい。忠告、ありがとうございます。","ENG":"O-oh, okay... Thanks for your advice.","TWN":"喔，那個……是，謝謝你的建議。"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DEALER_NPC_HAVEN_NULL","text":{"KOREA":"심사위원 분들 오셨습니다.","JPN":"審査員が来ました。","ENG":"Our judges have arrived.","TWN":"評審團已經抵達會場。"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEALER_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"좋아! 이제 시작할 차례로군!","JPN":"よし！　始めるぞ！","ENG":"Great! The show's about to start!","TWN":"來吧！決戰時刻！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"먼저 우리의 춤을 심사해 줄 심사위원들을 소개하지!","JPN":"まず、俺たちのダンスを審査してくれる審査員を紹介しよう！","ENG":"First, let me introduce you to our judges!","TWN":"先介紹一下負責打分數的評審團！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};